import { useEffect, useState } from "react";
import { getEvidenciaById } from "../backend/controllers/evidencias";

const FantasmaCard = ({ fantasma }) => {
  const [prueba, setPrueba] = useState([]);

  useEffect(() => {
    getEvidenciaById(fantasma.id).then((data)=>setPrueba(data))
  }, []);
  return (
    <>
      <div style={{padding:"10px", margin:"10px", display:"inline-block"}}>
        <h3>{fantasma.nombre}</h3>
        <span>Prueba1</span>
        <span>Prueba2</span>
        <span>Prueba3</span>
      </div>
    </>
  );
};

export default FantasmaCard;
